SELECT l.*, ste.site_nm AS site_nm, usr.user_nm AS user_nm, cd_lr.code_label AS result_cd_nm FROM syh_user_login_log l LEFT JOIN sy_site ste ON ste.site_id = l.site_id LEFT JOIN sy_user usr ON usr.user_id = l.user_id LEFT JOIN sy_code cd_lr ON cd_lr.code_grp = 'LOGIN_RESULT' AND cd_lr.code_value = l.result_cd
ORDER BY l.log_id ASC ORDER BY l.log_id DESC ORDER BY l.reg_date ASC ORDER BY l.reg_date DESC ORDER BY l.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

